#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long v,x;
    bool operator<(const node&b)const
    {
        return v<b.v;
    }
}a[1000010];
bool cmp(node x,node y)
{
    return x.x<y.x;
}
long long ans;
const long long mod=998244353;
void cdq(long long l,long long r)
{
    if(l==r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    cdq(l,mid);
    cdq(mid+1,r);
    long long suml=0,sumr=0;
    for(long long i=l;i<=mid;i++)
    {
        sumr+=a[i].x;
    }
    for(long long i=l,j=mid+1;j<=r;j++)
    {
        while(i<=mid&&a[i].x<=a[j].x)
        {
            suml+=a[i].x;
            sumr-=a[i].x;
            i++;
        }
        ans+=(a[j].v*((i-l)*a[j].x-suml+sumr-(mid-i+1)*a[j].x))%mod;
        ans%=mod;
    }
    sort(a+l,a+1+r,cmp);
}
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&a[i].v,&a[i].x);
    }
    sort(a+1,a+1+n);
    cdq(1,n);
    printf("%lld",ans);
    return 0;
}
